mapper.update:
UPDATE doc_asset_ref
SET is_deleted = 1,
    deletor_id = #{deletorId},
    delete_time = #{deleteTime}
WHERE document_id = #{documentId}
  AND ref_scope = #{refScope}
  AND is_deleted = 0

mapper.select:
SELECT COUNT(1)
FROM doc_asset_ref
WHERE document_id = #{documentId}
  AND asset_id = #{assetId}
  AND ref_scope = #{refScope}
  AND is_deleted = 0

SELECT asset_id
FROM doc_asset_ref
WHERE document_id = #{documentId}
  AND ref_scope = #{refScope}
  AND is_deleted = 0
ORDER BY asset_id
